# test_final_state.py

import os
import pytest

def test_vm_executable_exists():
    """Check if the compiled VM executable exists."""
    file_path = "/home/user/vm"
    assert os.path.isfile(file_path), f"The executable {file_path} does not exist. Did you compile vm.c?"
    assert os.access(file_path, os.X_OK), f"The file {file_path} is not executable."

def test_test_bin_exists():
    """Check if the generated bytecode test file exists."""
    file_path = "/home/user/test.bin"
    assert os.path.isfile(file_path), f"The bytecode file {file_path} does not exist."

def test_test_result_log():
    """Check if the test result log exists and contains the correct sum."""
    file_path = "/home/user/test_result.log"
    assert os.path.isfile(file_path), f"The log file {file_path} does not exist. Did you run the VM and redirect output?"

    with open(file_path, "r") as f:
        content = f.read()

    assert content.strip() == "210", f"Expected the log file to contain '210', but got '{content.strip()}'."